UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"Where is the vehicle located?","eyebrow":"Step 1 of 5","beschreibung":"We find the right assessor in your region."},"tr":{"titel":"Araç nerede bulunuyor?","eyebrow":"Adım 1 / 5","beschreibung":"Bölgenizde uygun bilirkişiyi sizin için buluyoruz."},"ar":{"titel":"أين تقع المركبة؟","eyebrow":"الخطوة 1 من 5","beschreibung":"نجد لك الخبير المناسب في منطقتك."},"ru":{"titel":"Где находится автомобиль?","eyebrow":"Шаг 1 из 5","beschreibung":"Мы найдём подходящего эксперта в Вашем регионе."},"pl":{"titel":"Gdzie znajduje się pojazd?","eyebrow":"Krok 1 z 5","beschreibung":"Znajdziemy dla Pana/Pani odpowiedniego rzeczoznawcę w Pana/Pani regionie."}}'::jsonb WHERE flow_key = 'gutachter-finden' AND phase_key = 'standort';
UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"When suits you?","eyebrow":"Step 2 of 5","beschreibung":"Available appointments in your region."},"tr":{"titel":"Sizin için ne zaman uygun?","eyebrow":"Adım 2 / 5","beschreibung":"Bölgenizdeki uygun randevular."},"ar":{"titel":"ما هو الوقت المناسب لك؟","eyebrow":"الخطوة 2 من 5","beschreibung":"المواعيد المتاحة في منطقتك."},"ru":{"titel":"Когда Вам удобно?","eyebrow":"Шаг 2 из 5","beschreibung":"Доступные даты в Вашем регионе."},"pl":{"titel":"Kiedy Panu/Pani pasuje?","eyebrow":"Krok 2 z 5","beschreibung":"Dostępne terminy w Pana/Pani regionie."}}'::jsonb WHERE flow_key = 'gutachter-finden' AND phase_key = 'termin';
UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"How should we support you?","eyebrow":"Step 3 of 5","beschreibung":"Full service with a lawyer or just the assessment — the choice is yours."},"tr":{"titel":"Size nasıl yardımcı olalım?","eyebrow":"Adım 3 / 5","beschreibung":"Avukatla birlikte tam hizmet ya da yalnızca ekspertiz — seçim sizin."},"ar":{"titel":"كيف يمكننا مساعدتك؟","eyebrow":"الخطوة 3 من 5","beschreibung":"خدمة كاملة مع محامٍ أو مجرد المعاينة — الخيار لك."},"ru":{"titel":"Как мы можем Вам помочь?","eyebrow":"Шаг 3 из 5","beschreibung":"Полный сервис с адвокатом или только экспертиза — выбор за Вами."},"pl":{"titel":"Jak możemy Panu/Pani pomóc?","eyebrow":"Krok 3 z 5","beschreibung":"Pełna obsługa z prawnikiem lub tylko ekspertyza — wybór należy do Pana/Pani."}}'::jsonb WHERE flow_key = 'gutachter-finden' AND phase_key = 'service';
UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"Which law firm should take over?","eyebrow":"Step 4 of 5","beschreibung":"With the partner law firm it costs you nothing and you have a direct contact person."},"tr":{"titel":"Hangi hukuk bürosu devralsın?","eyebrow":"Adım 4 / 5","beschreibung":"Partner hukuk bürosunda size hiçbir ücrete mal olmaz ve doğrudan bir muhatabınız olur."},"ar":{"titel":"أي مكتب محاماة يتولى القضية؟","eyebrow":"الخطوة 4 من 5","beschreibung":"مع مكتب المحاماة الشريك لا يكلفك ذلك شيئًا ويكون لديك جهة اتصال مباشرة."},"ru":{"titel":"Какая юридическая фирма возьмётся за дело?","eyebrow":"Шаг 4 из 5","beschreibung":"С партнёрской юридической фирмой это для Вас бесплатно, и у Вас есть прямое контактное лицо."},"pl":{"titel":"Która kancelaria ma się tym zająć?","eyebrow":"Krok 4 z 5","beschreibung":"W kancelarii partnerskiej nic to Pana/Panią nie kosztuje i ma Pan/Pani bezpośrednią osobę kontaktową."}}'::jsonb WHERE flow_key = 'gutachter-finden' AND phase_key = 'kanzlei';
UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"Your contact details","eyebrow":"Step 5 of 5","beschreibung":"So that we can confirm the appointment."},"tr":{"titel":"İletişim bilgileriniz","eyebrow":"Adım 5 / 5","beschreibung":"Randevuyu onaylayabilmemiz için."},"ar":{"titel":"بيانات الاتصال الخاصة بك","eyebrow":"الخطوة 5 من 5","beschreibung":"حتى نتمكن من تأكيد الموعد."},"ru":{"titel":"Ваши контактные данные","eyebrow":"Шаг 5 из 5","beschreibung":"Чтобы мы могли подтвердить дату."},"pl":{"titel":"Pana/Pani dane kontaktowe","eyebrow":"Krok 5 z 5","beschreibung":"Abyśmy mogli potwierdzić termin."}}'::jsonb WHERE flow_key = 'gutachter-finden' AND phase_key = 'kontakt';
UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"Your vehicle","eyebrow":"Step 1","beschreibung":"Take a photo of the vehicle registration — we automatically read out the licence plate, manufacturer and owner."},"tr":{"titel":"Aracınız","eyebrow":"Adım 1","beschreibung":"Ruhsatın fotoğrafını çekin — plakayı, üreticiyi ve sahibini otomatik olarak okuyoruz."},"ar":{"titel":"مركبتك","eyebrow":"الخطوة 1","beschreibung":"صوّر رخصة المركبة — نقرأ رقم اللوحة والشركة المصنّعة والمالك تلقائيًا."},"ru":{"titel":"Ваш автомобиль","eyebrow":"Шаг 1","beschreibung":"Сфотографируйте свидетельство о регистрации — мы автоматически считаем номерной знак, производителя и владельца."},"pl":{"titel":"Pana/Pani pojazd","eyebrow":"Krok 1","beschreibung":"Proszę sfotografować dowód rejestracyjny — automatycznie odczytamy numer rejestracyjny, producenta i właściciela."}}'::jsonb WHERE flow_key = 'kunde-onboarding' AND phase_key = 'fahrzeug';
UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"What happened?","eyebrow":"Step 1","beschreibung":"Briefly describe how the accident occurred."},"tr":{"titel":"Ne oldu?","eyebrow":"Adım 1","beschreibung":"Kazanın nasıl meydana geldiğini kısaca anlatın."},"ar":{"titel":"ماذا حدث؟","eyebrow":"الخطوة 1","beschreibung":"صِف باختصار كيف وقع الحادث."},"ru":{"titel":"Что произошло?","eyebrow":"Шаг 1","beschreibung":"Кратко опишите, как произошла авария."},"pl":{"titel":"Co się stało?","eyebrow":"Krok 1","beschreibung":"Proszę krótko opisać, jak doszło do wypadku."}}'::jsonb WHERE flow_key = 'kunde-onboarding' AND phase_key = 'hergang';
UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"How should we support you?","eyebrow":"Step 2","beschreibung":"Full service with a lawyer or just the assessment?"},"tr":{"titel":"Size nasıl yardımcı olalım?","eyebrow":"Adım 2","beschreibung":"Avukatla tam hizmet mi yoksa yalnızca ekspertiz mi?"},"ar":{"titel":"كيف يمكننا مساعدتك؟","eyebrow":"الخطوة 2","beschreibung":"خدمة كاملة مع محامٍ أم مجرد المعاينة؟"},"ru":{"titel":"Как мы можем Вам помочь?","eyebrow":"Шаг 2","beschreibung":"Полный сервис с адвокатом или только экспертиза?"},"pl":{"titel":"Jak możemy Panu/Pani pomóc?","eyebrow":"Krok 2","beschreibung":"Pełna obsługa z prawnikiem czy tylko ekspertyza?"}}'::jsonb WHERE flow_key = 'kunde-onboarding' AND phase_key = 'service';
UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"Which law firm?","eyebrow":"Step 3","beschreibung":"The choice is yours. With a partner law firm it costs you nothing."},"tr":{"titel":"Hangi hukuk bürosu?","eyebrow":"Adım 3","beschreibung":"Seçim sizin. Partner hukuk bürosunda size hiçbir ücrete mal olmaz."},"ar":{"titel":"أي مكتب محاماة؟","eyebrow":"الخطوة 3","beschreibung":"الخيار لك. مع مكتب محاماة شريك لا يكلفك ذلك شيئًا."},"ru":{"titel":"Какая юридическая фирма?","eyebrow":"Шаг 3","beschreibung":"Выбор за Вами. С партнёрской юридической фирмой это для Вас бесплатно."},"pl":{"titel":"Która kancelaria?","eyebrow":"Krok 3","beschreibung":"Wybór należy do Pana/Pani. W kancelarii partnerskiej nic to Pana/Panią nie kosztuje."}}'::jsonb WHERE flow_key = 'kunde-onboarding' AND phase_key = 'kanzlei';
UPDATE onboarding_phasen SET i18n = '{"en":{"titel":"Sign the security assignment (SA)","eyebrow":"Step 4","beschreibung":"So that we can bill the assessor directly with the insurer."},"tr":{"titel":"Teminat temliki (SA) imzalayın","eyebrow":"Adım 4","beschreibung":"Bilirkişiyi doğrudan sigorta şirketiyle faturalandırabilmemiz için."},"ar":{"titel":"وقّع على حوالة الضمان (SA)","eyebrow":"الخطوة 4","beschreibung":"حتى نتمكن من محاسبة الخبير مباشرة مع شركة التأمين."},"ru":{"titel":"Подпишите обеспечительную уступку (SA)","eyebrow":"Шаг 4","beschreibung":"Чтобы мы могли рассчитываться с экспертом напрямую через страховую компанию."},"pl":{"titel":"Proszę podpisać cesję zabezpieczającą (SA)","eyebrow":"Krok 4","beschreibung":"Abyśmy mogli rozliczać rzeczoznawcę bezpośrednio z ubezpieczycielem."}}'::jsonb WHERE flow_key = 'kunde-onboarding' AND phase_key = 'sa';
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Street, postcode, city","hint":"Address where the vehicle is to be inspected","placeholder":"e.g. Musterstraße 12, 50667 Köln"},"tr":{"label":"Sokak, posta kodu, şehir","hint":"Aracın inceleneceği adres","placeholder":"örn. Musterstraße 12, 50667 Köln"},"ar":{"label":"الشارع، الرمز البريدي، المدينة","hint":"العنوان الذي ستتم فيه معاينة المركبة","placeholder":"مثال: Musterstraße 12, 50667 Köln"},"ru":{"label":"Улица, индекс, город","hint":"Адрес, где будет осмотрен автомобиль","placeholder":"напр. Musterstraße 12, 50667 Köln"},"pl":{"label":"Ulica, kod pocztowy, miasto","hint":"Adres, pod którym pojazd ma zostać oględziny","placeholder":"np. Musterstraße 12, 50667 Köln"}}'::jsonb WHERE feld_key = 'besichtigungsort' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'standort');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"How urgently do you need the appointment?","optionen":{"sofort":{"label":"Immediately (today)"},"heute":{"label":"Tomorrow"},"tage":{"label":"In the next few days"}}},"tr":{"label":"Randevuya ne kadar acil ihtiyacınız var?","optionen":{"sofort":{"label":"Hemen (bugün)"},"heute":{"label":"Yarın"},"tage":{"label":"Önümüzdeki birkaç gün içinde"}}},"ar":{"label":"ما مدى استعجالك للموعد؟","optionen":{"sofort":{"label":"فورًا (اليوم)"},"heute":{"label":"غدًا"},"tage":{"label":"في الأيام القليلة القادمة"}}},"ru":{"label":"Насколько срочно Вам нужна дата?","optionen":{"sofort":{"label":"Сразу (сегодня)"},"heute":{"label":"Завтра"},"tage":{"label":"В ближайшие дни"}}},"pl":{"label":"Jak pilnie potrzebuje Pan/Pani terminu?","optionen":{"sofort":{"label":"Natychmiast (dziś)"},"heute":{"label":"Jutro"},"tage":{"label":"W ciągu najbliższych dni"}}}}'::jsonb WHERE feld_key = 'wunschtermin_wann' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'termin');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Choose an available appointment","hint":"All displayed times are still available with the selected assessor."},"tr":{"label":"Boş bir randevu seçin","hint":"Gösterilen tüm saatler seçilen bilirkişide hâlâ müsait."},"ar":{"label":"اختر موعدًا متاحًا","hint":"جميع الأوقات المعروضة لا تزال متاحة لدى الخبير المختار."},"ru":{"label":"Выберите свободную дату","hint":"Все показанные время ещё доступны у выбранного эксперта."},"pl":{"label":"Proszę wybrać wolny termin","hint":"Wszystkie wyświetlane godziny są nadal dostępne u wybranego rzeczoznawcy."}}'::jsonb WHERE feld_key = 'wunschtermin' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'termin');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Scope of service","hint":"With \"Full service\" we work together with our partner law firm LexDrive — free of charge for you, we handle everything.","optionen":{"komplett":{"label":"Full service (recommended)","description":"Lawyer + power of attorney included — 0 EUR, we handle everything for you"},"nur_gutachter":{"label":"Assessment only","description":"You settle the claim yourself with the other party''s insurer"}}},"tr":{"label":"Hizmet kapsamı","hint":"\"Tam hizmet\" seçeneğinde partner hukuk büromuz LexDrive ile birlikte çalışıyoruz — sizin için ücretsiz, her şeyi biz hallederiz.","optionen":{"komplett":{"label":"Tam hizmet (önerilir)","description":"Avukat + vekâletname dâhil — 0 EUR, her şeyi sizin için hallederiz"},"nur_gutachter":{"label":"Yalnızca ekspertiz","description":"Tazminatı karşı tarafın sigorta şirketiyle kendiniz halledersiniz"}}},"ar":{"label":"نطاق الخدمة","hint":"مع \"الخدمة الكاملة\" نعمل مع مكتب المحاماة الشريك LexDrive — مجانًا لك، نتولى كل شيء.","optionen":{"komplett":{"label":"الخدمة الكاملة (موصى بها)","description":"يشمل محاميًا + توكيلًا — 0 EUR، نتولى كل شيء نيابةً عنك"},"nur_gutachter":{"label":"المعاينة فقط","description":"تتولى التسوية بنفسك مع شركة تأمين الطرف الآخر"}}},"ru":{"label":"Объём услуг","hint":"При выборе «Полный сервис» мы работаем вместе с нашей партнёрской юридической фирмой LexDrive — для Вас бесплатно, мы берём всё на себя.","optionen":{"komplett":{"label":"Полный сервис (рекомендуется)","description":"Адвокат + доверенность включены — 0 EUR, мы берём всё на себя за Вас"},"nur_gutachter":{"label":"Только экспертиза","description":"Вы сами урегулируете дело со страховой компанией другой стороны"}}},"pl":{"label":"Zakres usługi","hint":"Przy opcji „Pełna obsługa\" współpracujemy z naszą kancelarią partnerską LexDrive — bezpłatnie dla Pana/Pani, my zajmiemy się wszystkim.","optionen":{"komplett":{"label":"Pełna obsługa (zalecane)","description":"Prawnik + pełnomocnictwo w cenie — 0 EUR, wszystkim zajmiemy się za Pana/Panią"},"nur_gutachter":{"label":"Tylko ekspertyza","description":"Sam/sama rozlicza Pan/Pani szkodę z ubezpieczycielem strony przeciwnej"}}}}'::jsonb WHERE feld_key = 'service_typ' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'service');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Choice of lawyer","optionen":{"partnerkanzlei":{"label":"Our partner law firm (recommended)","description":"LexDrive — specialised in motor vehicle claims, 0 EUR for you, they take care of the power of attorney and everything else"},"eigene_kanzlei":{"label":"My own law firm","description":"You give us the contact details, we hand over the package"},"keine_kanzlei":{"label":"No lawyer","description":"You settle the claim yourself — no legal support"}}},"tr":{"label":"Avukat seçimi","optionen":{"partnerkanzlei":{"label":"Partner hukuk büromuz (önerilir)","description":"LexDrive — araç hasarları konusunda uzman, sizin için 0 EUR, vekâletname ve diğer her şeyle ilgilenirler"},"eigene_kanzlei":{"label":"Kendi hukuk büromu","description":"İletişim bilgilerini bize verirsiniz, paketi biz devrederiz"},"keine_kanzlei":{"label":"Avukat yok","description":"Tazminatı kendiniz halledersiniz — avukat desteği olmadan"}}},"ar":{"label":"اختيار المحامي","optionen":{"partnerkanzlei":{"label":"مكتب المحاماة الشريك لدينا (موصى به)","description":"LexDrive — متخصص في أضرار المركبات، 0 EUR لك، يتولون التوكيل وكل ما يتبع ذلك"},"eigene_kanzlei":{"label":"مكتب المحاماة الخاص بي","description":"تعطينا بيانات الاتصال، ونحن نسلّم الملف"},"keine_kanzlei":{"label":"بدون محامٍ","description":"تتولى التسوية بنفسك — دون مرافقة محامٍ"}}},"ru":{"label":"Выбор адвоката","optionen":{"partnerkanzlei":{"label":"Наша партнёрская юридическая фирма (рекомендуется)","description":"LexDrive — специализируется на автомобильных ущербах, 0 EUR для Вас, они занимаются доверенностью и всем остальным"},"eigene_kanzlei":{"label":"Моя собственная юридическая фирма","description":"Вы даёте нам контактные данные, мы передаём пакет"},"keine_kanzlei":{"label":"Без адвоката","description":"Вы сами урегулируете дело — без сопровождения адвоката"}}},"pl":{"label":"Wybór prawnika","optionen":{"partnerkanzlei":{"label":"Nasza kancelaria partnerska (zalecane)","description":"LexDrive — wyspecjalizowana w szkodach komunikacyjnych, 0 EUR dla Pana/Pani, zajmuje się pełnomocnictwem i wszystkim pozostałym"},"eigene_kanzlei":{"label":"Moja własna kancelaria","description":"Przekazuje nam Pan/Pani dane kontaktowe, my przekazujemy dokumentację"},"keine_kanzlei":{"label":"Bez prawnika","description":"Sam/sama rozlicza Pan/Pani szkodę — bez wsparcia prawnika"}}}}'::jsonb WHERE feld_key = 'kanzlei_wunsch' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'kanzlei');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"First name","placeholder":"Max"},"tr":{"label":"Ad","placeholder":"Max"},"ar":{"label":"الاسم الأول","placeholder":"Max"},"ru":{"label":"Имя","placeholder":"Max"},"pl":{"label":"Imię","placeholder":"Max"}}'::jsonb WHERE feld_key = 'vorname' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'kontakt');
