UPDATE onboarding_felder SET i18n = '{"en":{"label":"Phone number","hint":"For appointment confirmation and queries.","placeholder":"+49 151 12345678"},"tr":{"label":"Telefon numarası","hint":"Randevu onayı ve sorular için.","placeholder":"+49 151 12345678"},"ar":{"label":"رقم الهاتف","hint":"لتأكيد الموعد والاستفسارات.","placeholder":"+49 151 12345678"},"ru":{"label":"Номер телефона","hint":"Для подтверждения даты и уточняющих вопросов.","placeholder":"+49 151 12345678"},"pl":{"label":"Numer telefonu","hint":"Do potwierdzenia terminu i pytań.","placeholder":"+49 151 12345678"}}'::jsonb WHERE feld_key = 'telefon' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'kontakt');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Email address","hint":"For order confirmation and delivery of the assessment.","placeholder":"max@beispiel.de"},"tr":{"label":"E-posta adresi","hint":"Sipariş onayı ve ekspertiz raporunun teslimi için.","placeholder":"max@beispiel.de"},"ar":{"label":"عنوان البريد الإلكتروني","hint":"لتأكيد الطلب وتسليم تقرير المعاينة.","placeholder":"max@beispiel.de"},"ru":{"label":"Адрес электронной почты","hint":"Для подтверждения заказа и доставки экспертизы.","placeholder":"max@beispiel.de"},"pl":{"label":"Adres e-mail","hint":"Do potwierdzenia zlecenia i dostarczenia ekspertyzy.","placeholder":"max@beispiel.de"}}'::jsonb WHERE feld_key = 'email' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'kontakt');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"How would you like to be contacted?","optionen":{"whatsapp":{"label":"WhatsApp"},"anruf":{"label":"Phone call"},"email":{"label":"Email"}}},"tr":{"label":"Sizinle nasıl iletişim kurmamızı istersiniz?","optionen":{"whatsapp":{"label":"WhatsApp"},"anruf":{"label":"Telefon görüşmesi"},"email":{"label":"E-posta"}}},"ar":{"label":"كيف تود أن نتواصل معك؟","optionen":{"whatsapp":{"label":"WhatsApp"},"anruf":{"label":"مكالمة هاتفية"},"email":{"label":"البريد الإلكتروني"}}},"ru":{"label":"Как с Вами связаться?","optionen":{"whatsapp":{"label":"WhatsApp"},"anruf":{"label":"Телефонный звонок"},"email":{"label":"Электронная почта"}}},"pl":{"label":"Jak mamy się z Panem/Panią kontaktować?","optionen":{"whatsapp":{"label":"WhatsApp"},"anruf":{"label":"Telefon"},"email":{"label":"E-mail"}}}}'::jsonb WHERE feld_key = 'bevorzugter_kanal' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'kontakt');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Your signature","hint":"With your signature you confirm the details and commission the appointment arrangement."},"tr":{"label":"İmzanız","hint":"İmzanızla bilgileri onaylar ve randevu aracılığını talep edersiniz."},"ar":{"label":"توقيعك","hint":"بتوقيعك تؤكد البيانات وتكلّفنا بترتيب الموعد."},"ru":{"label":"Ваша подпись","hint":"Своей подписью Вы подтверждаете данные и поручаете организацию даты."},"pl":{"label":"Pana/Pani podpis","hint":"Składając podpis, potwierdza Pan/Pani dane i zleca pośrednictwo w ustaleniu terminu."}}'::jsonb WHERE feld_key = 'unterschrift' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'kontakt');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"I consent to the processing of my data in accordance with the privacy policy.","hint":"Your data is used exclusively to arrange the appointment and is not passed on to third parties."},"tr":{"label":"Verilerimin gizlilik politikası uyarınca işlenmesini kabul ediyorum.","hint":"Verileriniz yalnızca randevu aracılığı için kullanılır ve üçüncü taraflarla paylaşılmaz."},"ar":{"label":"أوافق على معالجة بياناتي وفقًا لسياسة الخصوصية.","hint":"تُستخدم بياناتك حصريًا لترتيب الموعد ولا يتم تمريرها إلى أطراف ثالثة."},"ru":{"label":"Я согласен на обработку моих данных в соответствии с политикой конфиденциальности.","hint":"Ваши данные используются исключительно для организации даты и не передаются третьим лицам."},"pl":{"label":"Wyrażam zgodę na przetwarzanie moich danych zgodnie z polityką prywatności.","hint":"Pana/Pani dane są wykorzystywane wyłącznie do pośrednictwa w ustaleniu terminu i nie są przekazywane osobom trzecim."}}'::jsonb WHERE feld_key = 'dsgvo_zustimmung' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'gutachter-finden' AND phase_key = 'kontakt');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Vehicle registration","hint":"Take a photo of the front of the vehicle registration — we extract the data automatically."},"tr":{"label":"Araç ruhsatı","hint":"Ruhsatın ön yüzünü fotoğraflayın — verileri otomatik olarak çıkarıyoruz."},"ar":{"label":"رخصة المركبة","hint":"صوّر الوجه الأمامي لرخصة المركبة — نستخرج البيانات تلقائيًا."},"ru":{"label":"Свидетельство о регистрации","hint":"Сфотографируйте лицевую сторону свидетельства о регистрации — мы извлечём данные автоматически."},"pl":{"label":"Dowód rejestracyjny","hint":"Proszę sfotografować przednią stronę dowodu rejestracyjnego — dane wyodrębnimy automatycznie."}}'::jsonb WHERE feld_key = 'fahrzeugschein_foto' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'kunde-onboarding' AND phase_key = 'fahrzeug');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Course of the accident in your own words","hint":"At least 3-4 sentences. What you saw / experienced yourself.","placeholder":"E.g.: I was stopped at the red light when the car behind drove into me..."},"tr":{"label":"Kendi kelimelerinizle kazanın seyri","hint":"En az 3-4 cümle. Kendi gördükleriniz / yaşadıklarınız.","placeholder":"Örn.: Kırmızı ışıkta duruyordum ki arkadaki araç bana arkadan çarptı..."},"ar":{"label":"مجريات الحادث بكلماتك الخاصة","hint":"ثلاث إلى أربع جمل على الأقل. ما رأيته / عشته بنفسك.","placeholder":"مثال: كنت متوقفًا عند الإشارة الحمراء عندما اصطدمت بي السيارة الخلفية من الخلف..."},"ru":{"label":"Ход аварии своими словами","hint":"Минимум 3-4 предложения. То, что Вы сами видели / пережили.","placeholder":"Напр.: Я стоял на красный свет, когда задняя машина въехала в меня..."},"pl":{"label":"Przebieg wypadku własnymi słowami","hint":"Co najmniej 3-4 zdania. To, co Pan/Pani sam(a) widział(a) / przeżył(a).","placeholder":"Np.: Stałem/Stałam na czerwonym świetle, gdy samochód z tyłu najechał na mnie..."}}'::jsonb WHERE feld_key = 'hergang_kunde_text' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'kunde-onboarding' AND phase_key = 'hergang');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Scope of service","hint":"With \"Full\" we work together with our partner law firm LexDrive — free of charge for you.","optionen":{"komplett":{"label":"Full service","description":"With lawyer + power of attorney — 0 EUR for you, we handle everything"},"nur_gutachter":{"label":"Assessment only","description":"You settle the claim yourself, we commission the assessor"}}},"tr":{"label":"Hizmet kapsamı","hint":"\"Tam\" seçeneğinde partner hukuk büromuz LexDrive ile birlikte çalışıyoruz — sizin için ücretsiz.","optionen":{"komplett":{"label":"Tam hizmet","description":"Avukat + vekâletname ile — sizin için 0 EUR, her şeyi biz hallederiz"},"nur_gutachter":{"label":"Yalnızca ekspertiz","description":"Tazminatı kendiniz halledersiniz, bilirkişiyi biz görevlendiririz"}}},"ar":{"label":"نطاق الخدمة","hint":"مع \"الكاملة\" نعمل مع مكتب المحاماة الشريك LexDrive — مجانًا لك.","optionen":{"komplett":{"label":"الخدمة الكاملة","description":"مع محامٍ + توكيل — 0 EUR لك، نتولى كل شيء"},"nur_gutachter":{"label":"المعاينة فقط","description":"تتولى التسوية بنفسك، ونحن نكلّف الخبير"}}},"ru":{"label":"Объём услуг","hint":"При выборе «Полный» мы работаем вместе с нашей партнёрской юридической фирмой LexDrive — для Вас бесплатно.","optionen":{"komplett":{"label":"Полный сервис","description":"С адвокатом + доверенностью — 0 EUR для Вас, мы берём всё на себя"},"nur_gutachter":{"label":"Только экспертиза","description":"Вы сами урегулируете дело, мы заказываем эксперта"}}},"pl":{"label":"Zakres usługi","hint":"Przy opcji „Pełna\" współpracujemy z naszą kancelarią partnerską LexDrive — bezpłatnie dla Pana/Pani.","optionen":{"komplett":{"label":"Pełna obsługa","description":"Z prawnikiem + pełnomocnictwem — 0 EUR dla Pana/Pani, zajmiemy się wszystkim"},"nur_gutachter":{"label":"Tylko ekspertyza","description":"Sam/sama rozlicza Pan/Pani szkodę, my zamawiamy rzeczoznawcę"}}}}'::jsonb WHERE feld_key = 'service_typ' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'kunde-onboarding' AND phase_key = 'service');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Choice of lawyer","optionen":{"partnerkanzlei":{"label":"Our partner law firm","description":"LexDrive — specialised in motor vehicle claims, 0 EUR"},"eigene_kanzlei":{"label":"My own law firm","description":"You give us the contact details, we hand over"},"keine_kanzlei":{"label":"No lawyer","description":"You settle the claim yourself, we only deliver the assessment"}}},"tr":{"label":"Avukat seçimi","optionen":{"partnerkanzlei":{"label":"Partner hukuk büromuz","description":"LexDrive — araç hasarları konusunda uzman, 0 EUR"},"eigene_kanzlei":{"label":"Kendi hukuk büromu","description":"İletişim bilgilerini bize verirsiniz, devri biz yaparız"},"keine_kanzlei":{"label":"Avukat yok","description":"Tazminatı kendiniz halledersiniz, biz yalnızca ekspertizi teslim ederiz"}}},"ar":{"label":"اختيار المحامي","optionen":{"partnerkanzlei":{"label":"مكتب المحاماة الشريك لدينا","description":"LexDrive — متخصص في أضرار المركبات، 0 EUR"},"eigene_kanzlei":{"label":"مكتب المحاماة الخاص بي","description":"تعطينا بيانات الاتصال، ونحن نسلّم الملف"},"keine_kanzlei":{"label":"بدون محامٍ","description":"تتولى التسوية بنفسك، ونحن نسلّم تقرير المعاينة فقط"}}},"ru":{"label":"Выбор адвоката","optionen":{"partnerkanzlei":{"label":"Наша партнёрская юридическая фирма","description":"LexDrive — специализируется на автомобильных ущербах, 0 EUR"},"eigene_kanzlei":{"label":"Моя собственная юридическая фирма","description":"Вы даёте нам контактные данные, мы передаём"},"keine_kanzlei":{"label":"Без адвоката","description":"Вы сами урегулируете дело, мы предоставляем только экспертизу"}}},"pl":{"label":"Wybór prawnika","optionen":{"partnerkanzlei":{"label":"Nasza kancelaria partnerska","description":"LexDrive — wyspecjalizowana w szkodach komunikacyjnych, 0 EUR"},"eigene_kanzlei":{"label":"Moja własna kancelaria","description":"Przekazuje nam Pan/Pani dane kontaktowe, my przekazujemy dalej"},"keine_kanzlei":{"label":"Bez prawnika","description":"Sam/sama rozlicza Pan/Pani szkodę, my dostarczamy tylko ekspertyzę"}}}}'::jsonb WHERE feld_key = 'kanzlei_wunsch' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'kunde-onboarding' AND phase_key = 'kanzlei');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"Your signature","hint":"Sign with mouse / finger. You can read the SA power of attorney again here."},"tr":{"label":"İmzanız","hint":"Fare / parmak ile imzalayın. SA vekâletnamesini burada tekrar okuyabilirsiniz."},"ar":{"label":"توقيعك","hint":"وقّع باستخدام الفأرة / الإصبع. يمكنك قراءة توكيل SA مرة أخرى هنا."},"ru":{"label":"Ваша подпись","hint":"Подпишите мышью / пальцем. Доверенность SA Вы можете прочитать здесь ещё раз."},"pl":{"label":"Pana/Pani podpis","hint":"Proszę podpisać myszą / palcem. Pełnomocnictwo SA może Pan/Pani ponownie przeczytać tutaj."}}'::jsonb WHERE feld_key = 'sa_signatur_data_url' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'kunde-onboarding' AND phase_key = 'sa');
UPDATE onboarding_felder SET i18n = '{"en":{"label":"I consent to the processing of my data in accordance with the privacy policy"},"tr":{"label":"Verilerimin gizlilik politikası uyarınca işlenmesini kabul ediyorum"},"ar":{"label":"أوافق على معالجة بياناتي وفقًا لسياسة الخصوصية"},"ru":{"label":"Я согласен на обработку моих данных в соответствии с политикой конфиденциальности"},"pl":{"label":"Wyrażam zgodę na przetwarzanie moich danych zgodnie z polityką prywatności"}}'::jsonb WHERE feld_key = 'dsgvo_onboarding' AND phase_id = (SELECT id FROM onboarding_phasen WHERE flow_key = 'kunde-onboarding' AND phase_key = 'sa');
